#define _DEFAULT_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <pthread.h>

/* == EXEMPLE =======================================
 * Echo via pipe + 2 threads (simplifie)
 * Un thread ecrit, l'autre lit et affiche.
 * ================================================= */
void *echo_writer(void *arg) {
    int *fd = (int *)arg;
    const char *texts[] = {"Hello", "World"};
    for (int i = 0; i < 2; i++) {
        write(fd[0], texts[i], strlen(texts[i]));
        usleep(5000);
    }
    close(fd[0]);
    return NULL;
}

void *echo_reader(void *arg) {
    int *fd = (int *)arg;
    char buf[64];
    ssize_t n;
    while ((n = read(fd[1], buf, sizeof(buf)-1)) > 0) {
        buf[n] = '\0';
        printf("Echo: %s\n", buf);
    }
    return NULL;
}

void example_simple_echo(void) {
    int pipefd[2];
    pipe(pipefd);
    pthread_t t_wr, t_rd;
    pthread_create(&t_wr, NULL, echo_writer, pipefd);
    pthread_create(&t_rd, NULL, echo_reader, pipefd);
    pthread_join(t_wr, NULL);
    pthread_join(t_rd, NULL);
    close(pipefd[1]);
    printf("Echo done.\n");
}
/* Resultat: Echo: Hello / Echo: World / Echo done. */

